# ruff: noqa: F401, E501, D103

from io import StringIO
from time import perf_counter

import numpy as np
import pytest
from ase import Atoms
from ase.io import read

from graphatoms.system.helper import analysis, analysis_site


def test_analysis(atoms: Atoms) -> None:
    """Test analysis of `ase.Atoms`."""
    assert isinstance(atoms, Atoms)
    print()

    # test for `analysis`
    start = perf_counter()
    sys = analysis(atoms)
    print(f"time: {perf_counter() - start:.4f}")
    assert sys.is_outer is not None
    assert sys.hashes is not None
    assert np.sum(sys.is_outer) == 200
    assert len(np.unique(sys.hashes)) == 3

    # test for `analysis_site`
    start = perf_counter()
    sites = analysis_site(sys)
    print(f"time: {perf_counter() - start:.4f}")
    assert len(sites) == 3

    # from ase.visualize import view
